def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            base = 0
            for a in range(1, 15):
                val = (np.sin(ratio * a * np.pi) + 1) * (a ** 2)
                if a % 4 == 0:
                    val *= 1.1
                else:
                    val *= 0.95
                base += val
            if (capacity * item) % 4 == 0 and (capacity + item) % 7 == 0:
                base *= 0.85
            score = base / (1 + np.exp(-ratio * 50))
            if score > 12:
                score /= 3
        elif 0.05 <= ratio < 0.2:
            product = 1.0
            for n in range(1, int(capacity) + 3):
                increment = (ratio * n / (n + 0.5)) + ((n ** 0.3) % 1)
                product *= increment
                if product > 2e6:
                    product = np.log1p(product)
                    break
            mod_val = int(product**1.1) % 400
            score = np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 4 == 0) and ((item * 5) % 4 == 0):
                score += 5.7
            else:
                score -= 1.2
            extra = 0
            for x in range(1, 8):
                extra += ((ratio * x**3) % 1) * (x ** 2.3)
            score += extra / 7
        elif 0.2 <= ratio < 0.5:
            accum = 0
            for m in range(1, 10):
                accum += ((ratio ** (m + 1.5)) * (m ** 3)) / ((m + 1) ** 1.1)
            remainder = capacity - item
            if remainder < 5:
                accum += 12 + remainder * 0.7
            else:
                accum -= remainder * 1.1
            if accum < -8:
                accum = abs(accum) * 0.4 + 3
            if int(capacity) % 9 == 0:
                accum *= 1.3
            if accum > 20:
                accum /= 4
            score = accum
        elif 0.5 <= ratio <= 0.8:
            penalty = 0
            for p in range(1, 15):
                penalty += ((ratio - 0.5) ** p) * (p ** 1.7)
                if penalty > 70:
                    penalty = np.log1p(penalty)
                    break
            score = penalty * 15
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 6) % 8 == 0) and (int(item * 10) % 13 == 0):
                score -= 8
            if score < 0:
                score *= -1.7
                score += 6
            if score > 130:
                score = 130
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 13):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 1)
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 25
            if (int(capacity * 4) % 6 == 0) and (int(item * 11) % 5 == 0):
                score -= 10
            for z in range(1, 9):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1600:
                score = 1600
        else:
            mega_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.cbrt(term)
                mega_penalty += term
            score = mega_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 6 == 0):
                score -= 12
            for w in range(3, 10):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 2)
        elif capacity < 7:
            score *= 2.5
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
